applicants = model.search([('job_order_ids', '!=', False)])
for applicant in applicants:
    applicant._compute_ai_match()

jobs = model.search([('state', 'in', ['active', 'posted']), ('ai_matching_enabled', '=', True)])
for job in jobs:
    job.action_find_matching_candidates()

# Send reminders for placements with upcoming documents due
placements = model.search([
    ('state', 'in', ['confirmed', 'active']),
    ('documents_due_date', '!=', False),
    ('documents_received', '=', False)
])
for placement in placements:
    if placement.days_until_documents_due and placement.days_until_documents_due <= 3 and placement.days_until_documents_due >= 0:
        placement.message_post(
            body='Reminder: Documents are due in %d days' % placement.days_until_documents_due,
            subject='Documents Due Soon',
            subtype_xmlid='mail.mt_comment'
        )

